import * as React from 'react'
import { Outlet } from 'react-router-dom'
import ObjectID from 'bson-objectid'
import { useDispatch } from 'react-redux'
import {
    fetchVideoLibrary,
    addWorkout,
    fetchWorkoutLibrary,
} from 'src/redux/actions/figgsLibrary'
import { debounce } from 'lodash'
function RequireAuth({ children }) {
    const dispatch = useDispatch()
    const [currentTab, setCurrentTab] = React.useState('videos')
    const [workoutData, setWorkoutData] = React.useState({
        _id: ObjectID().toString(),
        Title: '',
        Exercise: [],
    })
    const reference = React.useRef(null)
    reference.current = workoutData

    const updateSilent = React.useCallback(
        debounce((Prog) => {
            let exercises = Prog.Exercise.filter(
                (i) => i?.title || i.media?.length
            )
            if (Prog.Title && exercises.length) {
                dispatch(addWorkout(Prog, '', true))
            }
        }, 3000),
        []
    )

    React.useEffect(() => {
        updateSilent(reference.current)
    }, [workoutData])

    React.useEffect(() => {
        dispatch(fetchVideoLibrary())
        dispatch(fetchWorkoutLibrary())
    }, [])
    return (
        <>
            <Outlet
                context={[
                    workoutData,
                    setWorkoutData,
                    currentTab,
                    setCurrentTab,
                ]}
            />
        </>
    )
}

export default RequireAuth
